export interface SiteIconData {
  [domainPrefix: string]: string;
}

// 从域名中提取前缀，用于匹配图标文件名
function extractDomainPrefix(domain: string): string {
  // 移除协议和www前缀
  let cleanDomain = domain.replace(/^https?:\/\//, '').replace(/^www\./, '');
  
  // 提取主域名部分（去掉顶级域名）
  const parts = cleanDomain.split('.');
  if (parts.length >= 2) {
    // 返回主域名部分，去掉顶级域名
    return parts[0];
  }
  
  return cleanDomain;
}

